import{_ as t,o as a,c as o,ai as n}from"./chunks/framework.2e-g_11C.js";const u=JSON.parse('{"title":"Configure a Data Model","description":"","frontmatter":{},"headers":[],"relativePath":"data-model-setup.md","filePath":"data-model-setup.md"}'),i={name:"data-model-setup.md"};function c(r,e,l,d,s,h){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="configure-a-data-model" tabindex="-1">Configure a Data Model <a class="header-anchor" href="#configure-a-data-model" aria-label="Permalink to “Configure a Data Model”">​</a></h1><p>This guide covers creating a collection, creating fields, and configuring relationships.</p><h2 id="creating-a-collection" tabindex="-1">Creating a Collection <a class="header-anchor" href="#creating-a-collection" aria-label="Permalink to “Creating a Collection”">​</a></h2><p>Log into the management interface as an administrator. If this is a brand-new project, you will be presented with the option to create your first collection. Otherwise, go to the settings module and create a new collection from the Data Model page.</p><p>Set the name of this collection to be <code>posts</code>, leaving all other options in both the collection setup and optional field pages as their defaults. You now have a new collection with only a primary key.</p><h2 id="creating-fields" tabindex="-1">Creating Fields <a class="header-anchor" href="#creating-fields" aria-label="Permalink to “Creating Fields”">​</a></h2><p>Your collection only has a primary key. From your new <code>posts</code> collection configuration page, click the <strong>Create Field</strong> button and select the Input interface. Set the key to <code>title</code> and leave all other options as their defaults.</p><p>Create another new field with a What You See Is What You Get (WYSIWYG) interface. Set the key to <code>content</code>.</p><h2 id="configuring-a-relationship" tabindex="-1">Configuring a Relationship <a class="header-anchor" href="#configuring-a-relationship" aria-label="Permalink to “Configuring a Relationship”">​</a></h2><p>Create a new collection called <code>authors</code>. In the new collection, create a new field with an Input interface and set the key to <code>name</code>.</p><p>Go to the <code>posts</code> collection configuration and create a new field with the Many to One interface and set the key to <code>author</code>. Set the related collection to <code>authors</code> and configure the Display Template to show just the author&#39;s name by selecting the <code>name</code> field.</p><p>Now that you have successfully configured a relationship between the two tables, you can start creating data.</p><p>In the module bar, go to the content module. Enter your <code>authors</code> collection and create 2 authors with the names <code>Ben Haynes</code> and <code>Rijk van Zanten</code>.</p><p>Enter the <code>posts</code> collection and create two posts, selecting an author from the Many to One interface.</p>',14)])])}const f=t(i,[["render",c]]);export{u as __pageData,f as default};
